export interface GameActionResult {
    success: boolean;
    type: ActionType;
    timestamp: number;
    data: Record<string, unknown>;
    effects: GameEffect[];
    state: StateChange;
    message: MessageData;
}

export type ActionType = 
    | 'combat_attack'
    | 'combat_skill'
    | 'combat_defend'
    | 'combat_flee'
    | 'card_play'
    | 'card_draw'
    | 'item_use'
    | 'item_equip'
    | 'item_unequip'
    | 'item_buy'
    | 'item_sell'
    | 'quest_accept'
    | 'quest_complete'
    | 'quest_update'
    | 'quest_abandon'
    | 'level_up'
    | 'explore'
    | 'dialogue';

export interface GameEffect {
    type: EffectType;
    source: string;
    target: string;
    value: number;
    element?: string;
    critical?: boolean;
    icon?: string;
    description: string;
}

export type EffectType = 
    | 'damage'
    | 'heal'
    | 'mana_restore'
    | 'mana_cost'
    | 'buff_apply'
    | 'buff_remove'
    | 'debuff_apply'
    | 'debuff_remove'
    | 'shield_add'
    | 'shield_remove'
    | 'gold_gain'
    | 'gold_loss'
    | 'exp_gain'
    | 'item_gain'
    | 'item_loss'
    | 'card_gain'
    | 'card_loss'
    | 'card_play'
    | 'energy_cost'
    | 'energy_gain'
    | 'stat_change';

export interface StateChange {
    player?: PlayerStateChange;
    combat?: CombatStateChange;
    inventory?: InventoryStateChange;
    quest?: QuestStateChange;
    card?: CardStateChange;
    [key: string]: unknown;
}

export interface PlayerStateChange {
    hp?: { before: number; after: number; max: number };
    mp?: { before: number; after: number; max: number };
    gold?: { before: number; after: number };
    exp?: { before: number; after: number; toNext: number };
    level?: { before: number; after: number };
    stats?: Record<string, { before: number; after: number }>;
    buffs?: BuffData[];
    debuffs?: DebuffData[];
}

export interface CombatStateChange {
    turn: number;
    phase: 'player_turn' | 'enemy_turn' | 'combat_start' | 'combat_end';
    playerHp?: { before: number; after: number; max: number };
    playerMp?: { before: number; after: number; max: number };
    playerShield?: number;
    enemy?: EnemyStateData;
    enemies?: EnemyStateData[];
    log: CombatLogEntry[];
    result?: 'victory' | 'defeat' | 'fled' | 'ongoing';
}

export interface EnemyStateData {
    id: string;
    name: string;
    icon?: string;
    hp: { before: number; after: number; max: number };
    mp: { before: number; after: number; max: number };
    shield: number;
    buffs: BuffData[];
    debuffs: DebuffData[];
    intent?: string;
    isAlive: boolean;
}

export interface BuffData {
    id: string;
    name: string;
    icon: string;
    stacks: number;
    duration: number;
    value: number;
    description: string;
}

export interface DebuffData {
    id: string;
    name: string;
    icon: string;
    stacks: number;
    duration: number;
    value: number;
    description: string;
}

export interface CombatLogEntry {
    turn: number;
    phase: 'player' | 'enemy';
    action: string;
    actor: string;
    target: string;
    effects: GameEffect[];
    timestamp: number;
}

export interface InventoryStateChange {
    itemsAdded?: ItemData[];
    itemsRemoved?: ItemData[];
    itemsChanged?: { item: ItemData; quantityBefore: number; quantityAfter: number }[];
    equipmentChanged?: { slot: string; before: ItemData | null; after: ItemData | null }[];
    goldChange?: { before: number; after: number };
    totalItems?: number;
    maxSlots?: number;
    itemCount?: number;
    maxItems?: number;
    goldDelta?: number;
    equippedItem?: ItemData;
    usedItem?: ItemData;
}

export interface ItemData {
    id: string;
    name: string;
    type: string;
    rarity: string;
    icon: string;
    description: string;
    quantity?: number;
    stats?: Record<string, number>;
    effect?: ItemEffectData;
}

export interface ItemEffectData {
    type: string;
    value: number;
    target: string;
    description: string;
}

export interface QuestStateChange {
    questId: string;
    questName: string;
    type?: string;
    status: 'accepted' | 'updated' | 'completed' | 'failed' | 'abandoned' | 'in_progress';
    objectives?: ObjectiveData[];
    progress?: { current: number; total: number; percentage: number };
    rewards?: RewardData;
    timeRemaining?: number;
    objectiveProgress?: { current: number; target: number };
}

export interface ObjectiveData {
    id: string;
    description: string;
    current: number;
    target: number;
    completed: boolean;
    progress: number;
}

export interface RewardData {
    exp?: number;
    gold?: number;
    items?: ItemData[];
    cards?: CardData[];
    description: string;
}

export interface CardStateChange {
    cardPlayed?: CardData;
    cardsDrawn?: CardData[];
    cardsDiscarded?: CardData[];
    cardsExhausted?: CardData[];
    handBefore?: string[];
    handAfter?: string[];
    deckSize?: number;
    discardPileSize?: number;
    energy?: { before: number; after: number; max: number };
    deckCount?: number;
    handCount?: number;
    discardCount?: number;
    maxEnergy?: number;
    drawnCards?: CardData[];
    playedCard?: CardData;
}

export interface CardData {
    id: string;
    name: string;
    type: string;
    rarity: string;
    cost: number;
    icon: string;
    description: string;
    effect: CardEffectData;
    upgraded?: boolean;
}

export interface CardEffectData {
    type: string;
    value: number;
    target: string;
    times?: number;
    description: string;
}

export interface MessageData {
    title: string;
    content: string;
    type: 'success' | 'error' | 'warning' | 'info' | 'combat' | 'reward';
    icon: string;
    details?: string[];
    highlights?: { text: string; color: string }[];
}

export class ResultBuilder {
    private result: GameActionResult;

    constructor(type: ActionType) {
        this.result = {
            success: true,
            type,
            timestamp: Date.now(),
            data: {},
            effects: [],
            state: {},
            message: {
                title: '',
                content: '',
                type: 'info',
                icon: '📋',
                details: [],
                highlights: []
            }
        };
    }

    setSuccess(success: boolean): this {
        this.result.success = success;
        return this;
    }

    setData(key: string, value: unknown): this {
        this.result.data[key] = value;
        return this;
    }

    addEffect(effect: GameEffect): this {
        this.result.effects.push(effect);
        return this;
    }

    addDamage(source: string, target: string, value: number, critical: boolean = false, element?: string): this {
        return this.addEffect({
            type: 'damage',
            source,
            target,
            value,
            element,
            critical,
            icon: critical ? '💥' : '⚔️',
            description: `${source} 对 ${target} 造成 ${value} 点伤害${critical ? ' (暴击!)' : ''}`
        });
    }

    addHeal(source: string, target: string, value: number): this {
        return this.addEffect({
            type: 'heal',
            source,
            target,
            value,
            icon: '💚',
            description: `${source} 恢复了 ${value} 点生命`
        });
    }

    addManaRestore(source: string, target: string, value: number): this {
        return this.addEffect({
            type: 'mana_restore',
            source,
            target,
            value,
            icon: '💙',
            description: `${source} 恢复了 ${value} 点魔力`
        });
    }

    addManaCost(source: string, target: string, value: number): this {
        return this.addEffect({
            type: 'mana_cost',
            source,
            target,
            value,
            icon: '💧',
            description: `${source} 消耗了 ${value} 点魔力`
        });
    }

    addShield(source: string, target: string, value: number): this {
        return this.addEffect({
            type: 'shield_add',
            source,
            target,
            value,
            icon: '🛡️',
            description: `${source} 获得了 ${value} 点护盾`
        });
    }

    addGoldGain(source: string, value: number): this {
        return this.addEffect({
            type: 'gold_gain',
            source,
            target: 'player',
            value,
            icon: '💰',
            description: `获得 ${value} 金币`
        });
    }

    addGoldLoss(source: string, value: number): this {
        return this.addEffect({
            type: 'gold_loss',
            source,
            target: 'player',
            value,
            icon: '💸',
            description: `消耗 ${value} 金币`
        });
    }

    addExpGain(source: string, value: number): this {
        return this.addEffect({
            type: 'exp_gain',
            source,
            target: 'player',
            value,
            icon: '⭐',
            description: `获得 ${value} 经验值`
        });
    }

    addItemGain(source: string, item: ItemData): this {
        return this.addEffect({
            type: 'item_gain',
            source,
            target: 'player',
            value: item.quantity ?? 1,
            icon: item.icon,
            description: `获得 ${item.name} x${item.quantity ?? 1}`
        });
    }

    addItemLoss(source: string, item: ItemData): this {
        return this.addEffect({
            type: 'item_loss',
            source,
            target: 'player',
            value: item.quantity ?? 1,
            icon: item.icon,
            description: `失去 ${item.name} x${item.quantity ?? 1}`
        });
    }

    addCardGain(source: string, card: CardData): this {
        return this.addEffect({
            type: 'card_gain',
            source,
            target: 'player',
            value: 1,
            icon: card.icon,
            description: `获得卡牌 ${card.name}`
        });
    }

    addCardLoss(source: string, card: CardData): this {
        return this.addEffect({
            type: 'card_loss',
            source,
            target: 'player',
            value: 1,
            icon: card.icon,
            description: `失去卡牌 ${card.name}`
        });
    }

    addBuff(source: string, target: string, buff: BuffData): this {
        return this.addEffect({
            type: 'buff_apply',
            source,
            target,
            value: buff.value,
            icon: buff.icon,
            description: `${target} 获得 ${buff.name} (${buff.stacks}层)`
        });
    }

    addDebuff(source: string, target: string, debuff: DebuffData): this {
        return this.addEffect({
            type: 'debuff_apply',
            source,
            target,
            value: debuff.value,
            icon: debuff.icon,
            description: `${target} 受到 ${debuff.name} (${debuff.stacks}层)`
        });
    }

    addEnergyCost(source: string, value: number): this {
        return this.addEffect({
            type: 'energy_cost',
            source,
            target: 'player',
            value,
            icon: '⚡',
            description: `消耗 ${value} 点能量`
        });
    }

    setPlayerState(state: PlayerStateChange): this {
        this.result.state.player = state;
        return this;
    }

    setCombatState(state: CombatStateChange): this {
        this.result.state.combat = state;
        return this;
    }

    setInventoryState(state: InventoryStateChange): this {
        this.result.state.inventory = state;
        return this;
    }

    setQuestState(state: QuestStateChange): this {
        this.result.state.quest = state;
        return this;
    }

    setCardState(state: CardStateChange): this {
        this.result.state.card = state;
        return this;
    }

    setMessage(title: string, content: string, type: MessageData['type'] = 'info', icon: string = '📋'): this {
        this.result.message = { ...this.result.message, title, content, type, icon };
        return this;
    }

    addDetail(detail: string): this {
        if (!this.result.message.details) {
            this.result.message.details = [];
        }
        this.result.message.details.push(detail);
        return this;
    }

    addHighlight(text: string, color: string): this {
        if (!this.result.message.highlights) {
            this.result.message.highlights = [];
        }
        this.result.message.highlights.push({ text, color });
        return this;
    }

    build(): GameActionResult {
        return this.result;
    }

    toJSON(): string {
        return JSON.stringify(this.result, null, 2);
    }
}

export function formatResultAsMarkdown(result: GameActionResult): string {
    const lines: string[] = [];
    
    lines.push(`## ${result.message.icon} ${result.message.title}`);
    lines.push('');
    lines.push(`**${result.message.content}**`);
    lines.push('');
    
    if (result.effects.length > 0) {
        lines.push('### 📊 效果列表');
        lines.push('');
        result.effects.forEach(effect => {
            const criticalText = effect.critical ? ' ⚡**暴击**' : '';
            lines.push(`- ${effect.icon} ${effect.description}${criticalText}`);
        });
        lines.push('');
    }
    
    if (result.state.player) {
        const ps = result.state.player;
        lines.push('### 👤 玩家状态变化');
        lines.push('');
        if (ps.hp) {
            const hpBar = createBar(ps.hp.after, ps.hp.max, '❤️');
            lines.push(`- **生命值**: ${ps.hp.before} → ${ps.hp.after}/${ps.hp.max} ${hpBar}`);
        }
        if (ps.mp) {
            const mpBar = createBar(ps.mp.after, ps.mp.max, '💙');
            lines.push(`- **魔力值**: ${ps.mp.before} → ${ps.mp.after}/${ps.mp.max} ${mpBar}`);
        }
        if (ps.gold) {
            lines.push(`- **金币**: ${ps.gold.before} → ${ps.gold.after} 💰`);
        }
        if (ps.exp) {
            lines.push(`- **经验**: ${ps.exp.before} → ${ps.exp.after}/${ps.exp.toNext} ⭐`);
        }
        if (ps.level && ps.level.before !== ps.level.after) {
            lines.push(`- **等级**: ${ps.level.before} → ${ps.level.after} 🎉`);
        }
        lines.push('');
    }
    
    if (result.state.combat) {
        const cs = result.state.combat;
        lines.push('### ⚔️ 战斗状态');
        lines.push('');
        lines.push(`- **回合**: ${cs.turn}`);
        lines.push(`- **阶段**: ${cs.phase}`);
        if (cs.result) {
            lines.push(`- **结果**: ${cs.result}`);
        }
        lines.push('');
    }
    
    if (result.state.quest) {
        const qs = result.state.quest;
        lines.push('### 📜 任务状态');
        lines.push('');
        lines.push(`- **任务**: ${qs.questName}`);
        lines.push(`- **状态**: ${qs.status}`);
        if (qs.progress) {
            lines.push(`- **进度**: ${qs.progress.current}/${qs.progress.total} (${qs.progress.percentage}%)`);
        }
        if (qs.objectives && qs.objectives.length > 0) {
            lines.push('');
            lines.push('**目标:**');
            qs.objectives.forEach(obj => {
                const check = obj.completed ? '✅' : '⬜';
                lines.push(`- ${check} ${obj.description} (${obj.current}/${obj.target})`);
            });
        }
        lines.push('');
    }
    
    if (result.message.details && result.message.details.length > 0) {
        lines.push('### 📝 详细信息');
        lines.push('');
        result.message.details.forEach(detail => {
            lines.push(`- ${detail}`);
        });
        lines.push('');
    }
    
    return lines.join('\n');
}

function createBar(current: number, max: number, icon: string): string {
    const percent = Math.floor((current / max) * 10);
    const filled = '█'.repeat(percent);
    const empty = '░'.repeat(10 - percent);
    return `${icon}${filled}${empty}`;
}

export default ResultBuilder;
